function UIAdaptKeyboard:UIAdaptKeyboard()
	self._inputText = nil
	self._adaptTrans = nil
	self._originPos = nil

	self._adaptTimer = nil

	self._lastHeight = -1

	self._isShowStopAdapt = false
end
------------------------------------------------------------------
function UIAdaptKeyboard:Create(inputText, adaptTrans, adaptOriginPos, moveTransAndroid, moveTransIos)
	self._uiCam = LGameUI.GetUICamera()

	self._originPos = adaptOriginPos
	self._adaptTrans = adaptTrans
	self._inputText = inputText

	--LogWarn("adaptTrans originPos = "..tostring(self._adaptTrans.anchoredPosition))
	if CS.IsOSIos() then
		inputText.shouldHideMobileInput = true
		self._moveTrans = moveTransIos
	else
		self._moveTrans = moveTransAndroid
	end

	self._isExportTouch = true

	if CS.IsOSIos() or CS.IsOSAndroid() then
		self:InitEvent()
	end
end

function UIAdaptKeyboard:InitEvent()
	self._inputText.onSelect:AddListener(function()

		self:StartAdapt()
	end)

	self._inputText.onDeselect:AddListener(function()

		self:onDeselect()
	end)

