------------------------------------------------------------------
function UIAdaptKeyboard:onDeselect()
	self:StopAdaptTimer()
	self:UpdateAdapt(true)
end

function UIAdaptKeyboard:StartAdapt()
	self:StopAdaptTimer()
	self._lastHeight = -1
	self._isShowStopAdapt = false
	self._lastSameTime = 0
	self._adaptTimer = LxTimer.LoopTimeCall(function ()
		self:UpdateAdapt()
	end,0)
end

function UIAdaptKeyboard:UpdateAdapt(bOrigin)
	if bOrigin then
		self._adaptTrans.anchoredPosition = self._originPos
		return
	end
	if CS.IsNullObject(self._moveTrans) then return end

	local keyboardHeight = 0

	local viewHeight = 0
	local screenHeight = UScreen.height

	keyboardHeight = 500

	if CS.IsOSIos() then
		viewHeight = Display.main.systemHeight
		keyboardHeight = 0
		if self._isExportTouch then
			local area = YXTouchManager.GetTouchScreenKeyboradArea()
			keyboardHeight = area.height
			--LogWarn(string.format("--------------keyboard area---------x =%s | y=%s | width=%s | height=%s",tostring(area.x),tostring(area.y),tostring(area.width),tostring(area.height)))
		end
	elseif CS.IsOSAndroid() then
		viewHeight = LGameQuality.SCREEN_HEIGHT_DEVICE
		keyboardHeight = viewHeight - LNativeHelper.GetUnityPlayerViewHeight()
	end

	if keyboardHeight < 0 then
		keyboardHeight = 0
	end

	--LogWarn(string.format("-----------------------viewHeight %s | screenHeight %s | keyboardHeight %s",tostring(viewHeight),tostring(screenHeight),tostring(keyboardHeight)))

	if keyboardHeight == self._lastHeight then
		return
	end
	self._lastHeight = keyboardHeight

	if CS.IsOSAndroid() then
		keyboardHeight = keyboardHeight + viewHeight * 0.08
	end

	local realHeight = keyboardHeight * (screenHeight / viewHeight)

	--LogWarn("real height = "..realHeight.." keyboardHeight="..keyboardHeight.." viewHeight="..viewHeight.." screenHeight"..screenHeight)
	local movePos = Vector3(0, realHeight, 0)
	local uiCam = self._uiCam
	local worldPos = uiCam:ScreenToWorldPoint(movePos)
	local startPos = uiCam:ScreenToWorldPoint(Vector3.zero)

	local worldCorners = self._moveTrans.transform:GetWorldCorners()
	local left = worldCorners[0]
	local right = worldCorners[2]

	local disY = left.y - worldPos.y
	--在上面不需要移动
	if disY >= 0 then

	else
		--left  在worldpos 的下面， 需要移动
		disY = -disY
		--printErrorN("aabbcc move height -___"..disY)

		local uiPos = self._adaptTrans.parent:InverseTransformPoint(Vector3(0,disY,0))
		local uiStartPos = self._adaptTrans.parent:InverseTransformPoint(Vector3.zero)
		--printErrorN("aabbcc move height -___"..(uiPos.y - uiStartPos.y))
		self._adaptTrans.anchoredPosition = self._originPos + Vector3(0, uiPos.y - uiStartPos.y, 0)
	end
end
-----------------------------------------------------------------
function UIAdaptKeyboard:StopAdaptTimer()
	if self._adaptTimer then
		LxTimer.DelayTimeStop(self._adaptTimer)
		self._adaptTimer = nil
	end
end
-----------------------------------------------------------------
function UIAdaptKeyboard:Destroy()
	if self._isDestroy then return end
	self:StopAdaptTimer()
	--if gLGameTouch then gLGameTouch:TouchUnRegister(LGameTouch.TOUCH_GAME) end
	table.removeall(self)
	self._isDestroy = true
end

return UIAdaptKeyboard